namespace RemoteDesktop.Common.Protocol;

// === 인증 ===

/// <summary>AUTH_CHALLENGE: Agent→Client nonce 전송</summary>
public class AuthChallengePayload
{
    public byte[] Nonce { get; set; } = new byte[32];

    public byte[] Serialize()
    {
        return Nonce;
    }

    public static AuthChallengePayload Deserialize(byte[] data)
    {
        var payload = new AuthChallengePayload();
        Buffer.BlockCopy(data, 0, payload.Nonce, 0, 32);
        return payload;
    }
}

/// <summary>AUTH_REQUEST: Client→Agent hash 전송</summary>
public class AuthRequestPayload
{
    public byte[] Hash { get; set; } = new byte[32];

    public byte[] Serialize()
    {
        return Hash;
    }

    public static AuthRequestPayload Deserialize(byte[] data)
    {
        var payload = new AuthRequestPayload();
        Buffer.BlockCopy(data, 0, payload.Hash, 0, 32);
        return payload;
    }
}

/// <summary>AUTH_RESPONSE: Agent→Client 결과 전송</summary>
public class AuthResponsePayload
{
    public bool Success { get; set; }
    public ushort Width { get; set; }
    public ushort Height { get; set; }

    public byte[] Serialize()
    {
        var data = new byte[5];
        data[0] = Success ? (byte)1 : (byte)0;
        BitConverter.GetBytes(Width).CopyTo(data, 1);
        BitConverter.GetBytes(Height).CopyTo(data, 3);
        return data;
    }

    public static AuthResponsePayload Deserialize(byte[] data)
    {
        return new AuthResponsePayload
        {
            Success = data[0] != 0,
            Width = BitConverter.ToUInt16(data, 1),
            Height = BitConverter.ToUInt16(data, 3)
        };
    }
}

// === 화면 ===

/// <summary>SCREEN_FULL: 전체 화면 JPEG</summary>
public class ScreenFullPayload
{
    public ushort Width { get; set; }
    public ushort Height { get; set; }
    public byte[] JpegData { get; set; } = [];

    public byte[] Serialize()
    {
        var data = new byte[4 + JpegData.Length];
        BitConverter.GetBytes(Width).CopyTo(data, 0);
        BitConverter.GetBytes(Height).CopyTo(data, 2);
        Buffer.BlockCopy(JpegData, 0, data, 4, JpegData.Length);
        return data;
    }

    public static ScreenFullPayload Deserialize(byte[] data)
    {
        return new ScreenFullPayload
        {
            Width = BitConverter.ToUInt16(data, 0),
            Height = BitConverter.ToUInt16(data, 2),
            JpegData = data[4..]
        };
    }
}

// === 마우스 ===

/// <summary>MOUSE_MOVE: 정규화 좌표 (0~1)</summary>
public class MouseMovePayload
{
    public float NormalizedX { get; set; }
    public float NormalizedY { get; set; }

    public byte[] Serialize()
    {
        var data = new byte[8];
        BitConverter.GetBytes(NormalizedX).CopyTo(data, 0);
        BitConverter.GetBytes(NormalizedY).CopyTo(data, 4);
        return data;
    }

    public static MouseMovePayload Deserialize(byte[] data)
    {
        return new MouseMovePayload
        {
            NormalizedX = BitConverter.ToSingle(data, 0),
            NormalizedY = BitConverter.ToSingle(data, 4)
        };
    }
}

/// <summary>MOUSE_CLICK: 클릭 이벤트</summary>
public class MouseClickPayload
{
    public float NormalizedX { get; set; }
    public float NormalizedY { get; set; }
    public byte Button { get; set; }  // 0=좌, 1=우, 2=중
    public bool IsDown { get; set; }

    public byte[] Serialize()
    {
        var data = new byte[10];
        BitConverter.GetBytes(NormalizedX).CopyTo(data, 0);
        BitConverter.GetBytes(NormalizedY).CopyTo(data, 4);
        data[8] = Button;
        data[9] = IsDown ? (byte)1 : (byte)0;
        return data;
    }

    public static MouseClickPayload Deserialize(byte[] data)
    {
        return new MouseClickPayload
        {
            NormalizedX = BitConverter.ToSingle(data, 0),
            NormalizedY = BitConverter.ToSingle(data, 4),
            Button = data[8],
            IsDown = data[9] != 0
        };
    }
}

/// <summary>MOUSE_SCROLL: 스크롤 이벤트</summary>
public class MouseScrollPayload
{
    public float NormalizedX { get; set; }
    public float NormalizedY { get; set; }
    public short Delta { get; set; }

    public byte[] Serialize()
    {
        var data = new byte[10];
        BitConverter.GetBytes(NormalizedX).CopyTo(data, 0);
        BitConverter.GetBytes(NormalizedY).CopyTo(data, 4);
        BitConverter.GetBytes(Delta).CopyTo(data, 8);
        return data;
    }

    public static MouseScrollPayload Deserialize(byte[] data)
    {
        return new MouseScrollPayload
        {
            NormalizedX = BitConverter.ToSingle(data, 0),
            NormalizedY = BitConverter.ToSingle(data, 4),
            Delta = BitConverter.ToInt16(data, 8)
        };
    }
}

// === 키보드 ===

/// <summary>KEY_EVENT: 키보드 이벤트</summary>
public class KeyEventPayload
{
    public ushort VirtualKey { get; set; }
    public ushort ScanCode { get; set; }
    public bool IsDown { get; set; }
    public bool IsExtended { get; set; }

    public byte[] Serialize()
    {
        var data = new byte[6];
        BitConverter.GetBytes(VirtualKey).CopyTo(data, 0);
        BitConverter.GetBytes(ScanCode).CopyTo(data, 2);
        data[4] = IsDown ? (byte)1 : (byte)0;
        data[5] = IsExtended ? (byte)1 : (byte)0;
        return data;
    }

    public static KeyEventPayload Deserialize(byte[] data)
    {
        return new KeyEventPayload
        {
            VirtualKey = BitConverter.ToUInt16(data, 0),
            ScanCode = BitConverter.ToUInt16(data, 2),
            IsDown = data[4] != 0,
            IsExtended = data[5] != 0
        };
    }
}

