using System.Net.Sockets;

namespace RemoteDesktop.Common.Protocol;

/// <summary>TCP 스트림에서 패킷 역직렬화</summary>
public class PacketReader
{
    private readonly NetworkStream _stream;
    private readonly byte[] _headerBuf = new byte[5]; // 4B 길이 + 1B 타입

    public PacketReader(NetworkStream stream)
    {
        _stream = stream;
    }

    /// <summary>패킷 1개 읽기 (블로킹)</summary>
    public async Task<Packet> ReadAsync(CancellationToken ct = default)
    {
        // 헤더 5바이트 읽기
        await ReadExactAsync(_headerBuf, 0, 5, ct);

        int length = BitConverter.ToInt32(_headerBuf, 0); // 타입(1B) + 페이로드(NB)
        var type = (PacketType)_headerBuf[4];

        int payloadLen = length - 1;
        byte[] payload = [];
        if (payloadLen > 0)
        {
            payload = new byte[payloadLen];
            await ReadExactAsync(payload, 0, payloadLen, ct);
        }

        return new Packet(type, payload);
    }

    /// <summary>지정 바이트 수만큼 정확히 읽기</summary>
    private async Task ReadExactAsync(byte[] buffer, int offset, int count, CancellationToken ct)
    {
        int totalRead = 0;
        while (totalRead < count)
        {
            int read = await _stream.ReadAsync(buffer, offset + totalRead, count - totalRead, ct);
            if (read == 0)
                throw new IOException("연결이 끊어졌습니다.");
            totalRead += read;
        }
    }
}

