using System.Net.Sockets;

namespace RemoteDesktop.Common.Protocol;

/// <summary>패킷을 TCP 스트림에 직렬화</summary>
public class PacketWriter
{
    private readonly NetworkStream _stream;
    private readonly SemaphoreSlim _writeLock = new(1, 1);

    public PacketWriter(NetworkStream stream)
    {
        _stream = stream;
    }

    /// <summary>패킷 전송 (스레드 안전)</summary>
    public async Task WriteAsync(Packet packet, CancellationToken ct = default)
    {
        int length = 1 + packet.Payload.Length; // 타입(1B) + 페이로드
        var header = new byte[5];
        BitConverter.GetBytes(length).CopyTo(header, 0);
        header[4] = (byte)packet.Type;

        await _writeLock.WaitAsync(ct);
        try
        {
            await _stream.WriteAsync(header, ct);
            if (packet.Payload.Length > 0)
                await _stream.WriteAsync(packet.Payload, ct);
            await _stream.FlushAsync(ct);
        }
        finally
        {
            _writeLock.Release();
        }
    }
}

