using System.Net.Sockets;
using RemoteDesktop.Common.Protocol;

namespace RemoteDesktop.Common.Network;

/// <summary>TCP 연결 래퍼 (패킷 송수신 + 하트비트)</summary>
public class TcpConnection : IDisposable
{
    private readonly TcpClient _client;
    private readonly NetworkStream _stream;
    public PacketReader Reader { get; }
    public PacketWriter Writer { get; }

    private Timer? _heartbeatTimer;
    private readonly CancellationTokenSource _cts = new();
    private bool _disposed;

    public bool IsConnected => _client.Connected;
    public string RemoteEndPoint => _client.Client.RemoteEndPoint?.ToString() ?? "unknown";

    public TcpConnection(TcpClient client)
    {
        _client = client;
        _client.NoDelay = true;
        _client.ReceiveBufferSize = 1024 * 1024;  // 1MB
        _client.SendBufferSize = 1024 * 1024;
        _stream = client.GetStream();
        Reader = new PacketReader(_stream);
        Writer = new PacketWriter(_stream);
    }

    /// <summary>하트비트 타이머 시작 (5초 간격)</summary>
    public void StartHeartbeat()
    {
        _heartbeatTimer = new Timer(async _ =>
        {
            try
            {
                await SendAsync(new Packet(PacketType.Heartbeat));
            }
            catch
            {
                // 연결 끊김 → 무시 (수신 루프에서 감지)
            }
        }, null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(5));
    }

    public Task SendAsync(Packet packet, CancellationToken ct = default)
    {
        return Writer.WriteAsync(packet, ct);
    }

    public Task<Packet> ReceiveAsync(CancellationToken ct = default)
    {
        return Reader.ReadAsync(ct);
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        _heartbeatTimer?.Dispose();
        _cts.Cancel();
        _cts.Dispose();
        try { _stream.Dispose(); } catch { }
        try { _client.Dispose(); } catch { }
    }
}

