using System.Security.Cryptography;
using System.Text;

namespace RemoteDesktop.Common.Auth;

/// <summary>챌린지-리스펀스 인증 (nonce + SHA256)</summary>
public static class ChallengeAuth
{
    /// <summary>32바이트 랜덤 nonce 생성</summary>
    public static byte[] GenerateNonce()
    {
        return RandomNumberGenerator.GetBytes(32);
    }

    /// <summary>SHA256(nonce + password) 해시 계산</summary>
    public static byte[] ComputeHash(byte[] nonce, string password)
    {
        var passwordBytes = Encoding.UTF8.GetBytes(password);
        var combined = new byte[nonce.Length + passwordBytes.Length];
        Buffer.BlockCopy(nonce, 0, combined, 0, nonce.Length);
        Buffer.BlockCopy(passwordBytes, 0, combined, nonce.Length, passwordBytes.Length);
        return SHA256.HashData(combined);
    }

    /// <summary>해시 검증</summary>
    public static bool Verify(byte[] nonce, string password, byte[] receivedHash)
    {
        var expectedHash = ComputeHash(nonce, password);
        return CryptographicOperations.FixedTimeEquals(expectedHash, receivedHash);
    }
}

