using System.Drawing;
using System.Drawing.Imaging;
using System.Runtime.InteropServices;
using Vortice.Direct3D;
using Vortice.Direct3D11;
using Vortice.DXGI;

namespace RemoteDesktop.Agent.Capture;

/// <summary>DXGI Desktop Duplication 화면 캡처</summary>
public class DxgiScreenCapturer : IScreenCapturer
{
    private ID3D11Device? _device;
    private ID3D11DeviceContext? _context;
    private IDXGIOutputDuplication? _duplication;
    private ID3D11Texture2D? _stagingTexture;

    public int Width { get; private set; }
    public int Height { get; private set; }

    private bool _disposed;

    public DxgiScreenCapturer()
    {
        Initialize();
    }

    private void Initialize()
    {
        // D3D11 디바이스 생성
        D3D11.D3D11CreateDevice(
            null,
            DriverType.Hardware,
            DeviceCreationFlags.BgraSupport,
            null,
            out _device,
            out _context);

        if (_device == null || _context == null)
            throw new Exception("D3D11 디바이스 생성 실패");

        // DXGI 팩토리에서 주 모니터 출력 가져오기
        using var dxgiDevice = _device.QueryInterface<IDXGIDevice>();
        using var adapter = dxgiDevice.GetAdapter();
        using var output = adapter.EnumOutputs(0);
        using var output1 = output.QueryInterface<IDXGIOutput1>();

        var outputDesc = output.Description;
        Width = outputDesc.DesktopCoordinates.Right - outputDesc.DesktopCoordinates.Left;
        Height = outputDesc.DesktopCoordinates.Bottom - outputDesc.DesktopCoordinates.Top;

        // Desktop Duplication 생성
        _duplication = output1.DuplicateOutput(_device);

        // 스테이징 텍스처 (GPU→CPU 복사용)
        var stagingDesc = new Texture2DDescription
        {
            Width = Width,
            Height = Height,
            MipLevels = 1,
            ArraySize = 1,
            Format = Vortice.DXGI.Format.B8G8R8A8_UNorm,
            SampleDescription = new SampleDescription(1, 0),
            Usage = ResourceUsage.Staging,
            CPUAccessFlags = CpuAccessFlags.Read,
            BindFlags = BindFlags.None
        };
        _stagingTexture = _device.CreateTexture2D(stagingDesc);
    }

    public Bitmap? CaptureFrame()
    {
        if (_duplication == null || _context == null || _stagingTexture == null)
            return null;

        IDXGIResource? resource = null;
        try
        {
            // 프레임 획득 (16ms 타임아웃)
            var result = _duplication.AcquireNextFrame(16, out _, out resource);
            if (result.Failure || resource == null)
                return null;

            using var texture = resource.QueryInterface<ID3D11Texture2D>();
            _context.CopyResource(_stagingTexture, texture);

            // GPU→CPU 매핑
            var mapped = _context.Map(_stagingTexture, 0, MapMode.Read);
            try
            {
                var bitmap = new Bitmap(Width, Height, PixelFormat.Format32bppArgb);
                var bmpData = bitmap.LockBits(
                    new Rectangle(0, 0, Width, Height),
                    ImageLockMode.WriteOnly,
                    PixelFormat.Format32bppArgb);

                // 행 단위 복사 (stride가 다를 수 있음)
                for (int y = 0; y < Height; y++)
                {
                    var srcPtr = mapped.DataPointer + y * mapped.RowPitch;
                    var dstPtr = bmpData.Scan0 + y * bmpData.Stride;
                    Buffer.MemoryCopy(srcPtr.ToPointer(), dstPtr.ToPointer(),
                        bmpData.Stride, Width * 4);
                }

                bitmap.UnlockBits(bmpData);
                return bitmap;
            }
            finally
            {
                _context.Unmap(_stagingTexture, 0);
            }
        }
        catch (SharpGen.Runtime.SharpGenException ex) when (
            ex.ResultCode.Code == Vortice.DXGI.ResultCode.AccessLost.Code)
        {
            // 해상도 변경/절전 복귀 → 재초기화
            Reinitialize();
            return null;
        }
        finally
        {
            resource?.Dispose();
            try { _duplication?.ReleaseFrame(); } catch { }
        }
    }

    private void Reinitialize()
    {
        CleanupResources();
        try { Initialize(); }
        catch { /* 다음 프레임에서 재시도 */ }
    }

    private void CleanupResources()
    {
        _stagingTexture?.Dispose();
        _stagingTexture = null;
        _duplication?.Dispose();
        _duplication = null;
        _context?.Dispose();
        _context = null;
        _device?.Dispose();
        _device = null;
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        CleanupResources();
        GC.SuppressFinalize(this);
    }
}

