using System.Drawing;
using System.Drawing.Imaging;

namespace RemoteDesktop.Agent.Encoding;

/// <summary>Bitmap → JPEG 바이트 배열 인코딩</summary>
public class JpegEncoder
{
    private readonly long _quality;
    private readonly ImageCodecInfo _jpegCodec;
    private readonly EncoderParameters _encoderParams;

    public JpegEncoder(int quality = 60)
    {
        _quality = quality;
        _jpegCodec = ImageCodecInfo.GetImageDecoders()
            .First(c => c.FormatID == ImageFormat.Jpeg.Guid);
        _encoderParams = new EncoderParameters(1)
        {
            Param = [new EncoderParameter(Encoder.Quality, _quality)]
        };
    }

    /// <summary>Bitmap을 JPEG 바이트 배열로 인코딩</summary>
    public byte[] Encode(Bitmap bitmap)
    {
        using var ms = new MemoryStream();
        bitmap.Save(ms, _jpegCodec, _encoderParams);
        return ms.ToArray();
    }
}

