using System.Text.Json;

namespace RemoteDesktop.Agent;

/// <summary>Agent 설정 (JSON 파일)</summary>
public class AgentConfig
{
    public int Port { get; set; } = 9500;
    public string Password { get; set; } = "remote";
    public int Fps { get; set; } = 15;
    public int JpegQuality { get; set; } = 60;

    private static readonly string ConfigPath = Path.Combine(
        AppDomain.CurrentDomain.BaseDirectory, "agent-config.json");

    public static AgentConfig Load()
    {
        if (File.Exists(ConfigPath))
        {
            var json = File.ReadAllText(ConfigPath);
            return JsonSerializer.Deserialize<AgentConfig>(json) ?? new AgentConfig();
        }
        var config = new AgentConfig();
        config.Save();
        return config;
    }

    public void Save()
    {
        var json = JsonSerializer.Serialize(this, new JsonSerializerOptions { WriteIndented = true });
        File.WriteAllText(ConfigPath, json);
    }

    /// <summary>FPS → 밀리초 간격</summary>
    public int CaptureIntervalMs => 1000 / Fps;
}

