using System.Runtime.InteropServices;
using static RemoteDesktop.Agent.Input.NativeMethods;

namespace RemoteDesktop.Agent.Input;

/// <summary>SendInput을 사용한 마우스/키보드 시뮬레이션</summary>
public class InputSimulator
{
    private readonly int _screenWidth;
    private readonly int _screenHeight;

    public InputSimulator()
    {
        _screenWidth = GetSystemMetrics(SM_CXSCREEN);
        _screenHeight = GetSystemMetrics(SM_CYSCREEN);
    }

    /// <summary>마우스 이동 (정규화 좌표 0~1)</summary>
    public void MouseMove(float nx, float ny)
    {
        // 절대 좌표 (0~65535)
        int absX = (int)(nx * 65535);
        int absY = (int)(ny * 65535);

        var input = new INPUT
        {
            type = INPUT_MOUSE,
            U = new InputUnion
            {
                mi = new MOUSEINPUT
                {
                    dx = absX,
                    dy = absY,
                    dwFlags = MOUSEEVENTF_MOVE | MOUSEEVENTF_ABSOLUTE
                }
            }
        };
        SendInput(1, [input], Marshal.SizeOf<INPUT>());
    }

    /// <summary>마우스 클릭</summary>
    public void MouseClick(float nx, float ny, byte button, bool isDown)
    {
        int absX = (int)(nx * 65535);
        int absY = (int)(ny * 65535);

        uint flags = MOUSEEVENTF_ABSOLUTE | MOUSEEVENTF_MOVE;
        flags |= button switch
        {
            0 => isDown ? MOUSEEVENTF_LEFTDOWN : MOUSEEVENTF_LEFTUP,
            1 => isDown ? MOUSEEVENTF_RIGHTDOWN : MOUSEEVENTF_RIGHTUP,
            2 => isDown ? MOUSEEVENTF_MIDDLEDOWN : MOUSEEVENTF_MIDDLEUP,
            _ => 0
        };

        var input = new INPUT
        {
            type = INPUT_MOUSE,
            U = new InputUnion
            {
                mi = new MOUSEINPUT
                {
                    dx = absX,
                    dy = absY,
                    dwFlags = flags
                }
            }
        };
        SendInput(1, [input], Marshal.SizeOf<INPUT>());
    }

    /// <summary>마우스 스크롤</summary>
    public void MouseScroll(float nx, float ny, short delta)
    {
        int absX = (int)(nx * 65535);
        int absY = (int)(ny * 65535);

        var input = new INPUT
        {
            type = INPUT_MOUSE,
            U = new InputUnion
            {
                mi = new MOUSEINPUT
                {
                    dx = absX,
                    dy = absY,
                    mouseData = delta,
                    dwFlags = MOUSEEVENTF_ABSOLUTE | MOUSEEVENTF_MOVE | MOUSEEVENTF_WHEEL
                }
            }
        };
        SendInput(1, [input], Marshal.SizeOf<INPUT>());
    }

    /// <summary>키보드 이벤트</summary>
    public void KeyEvent(ushort virtualKey, ushort scanCode, bool isDown, bool isExtended)
    {
        uint flags = KEYEVENTF_SCANCODE;
        if (!isDown) flags |= KEYEVENTF_KEYUP;
        if (isExtended) flags |= KEYEVENTF_EXTENDEDKEY;

        var input = new INPUT
        {
            type = INPUT_KEYBOARD,
            U = new InputUnion
            {
                ki = new KEYBDINPUT
                {
                    wVk = virtualKey,
                    wScan = scanCode,
                    dwFlags = flags
                }
            }
        };
        SendInput(1, [input], Marshal.SizeOf<INPUT>());
    }
}

