using System.Net;
using System.Net.Sockets;
using RemoteDesktop.Agent.Capture;
using RemoteDesktop.Agent.Encoding;
using RemoteDesktop.Agent.Input;
using RemoteDesktop.Common.Network;

namespace RemoteDesktop.Agent.Server;

/// <summary>TCP 리스너 + 세션 관리 (동시 1개 연결)</summary>
public class AgentServer : IDisposable
{
    private readonly AgentConfig _config;
    private TcpListener? _listener;
    private ClientSession? _currentSession;
    private IScreenCapturer? _capturer;
    private JpegEncoder? _encoder;
    private InputSimulator? _input;
    private CancellationTokenSource? _cts;
    private bool _disposed;

    public event Action<string>? Log;
    public event Action<bool>? ConnectionChanged; // true=연결, false=해제
    public bool IsRunning { get; private set; }

    public AgentServer(AgentConfig config)
    {
        _config = config;
    }

    public void Start()
    {
        if (IsRunning) return;

        _capturer = new DxgiScreenCapturer();
        _encoder = new JpegEncoder(_config.JpegQuality);
        _input = new InputSimulator();
        _cts = new CancellationTokenSource();

        _listener = new TcpListener(IPAddress.Any, _config.Port);
        _listener.Start();
        IsRunning = true;

        Log?.Invoke($"서버 시작 (포트: {_config.Port}, 해상도: {_capturer.Width}x{_capturer.Height})");

        _ = AcceptLoopAsync(_cts.Token);
    }

    public void Stop()
    {
        if (!IsRunning) return;
        IsRunning = false;

        _cts?.Cancel();
        _currentSession?.Dispose();
        _currentSession = null;
        _listener?.Stop();
        _capturer?.Dispose();
        _cts?.Dispose();

        Log?.Invoke("서버 중지");
    }

    private async Task AcceptLoopAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested && _listener != null)
        {
            try
            {
                var client = await _listener.AcceptTcpClientAsync(ct);
                var connection = new TcpConnection(client);

                Log?.Invoke($"접속: {connection.RemoteEndPoint}");

                // 기존 세션 종료 (동시 1개 제한)
                if (_currentSession != null)
                {
                    Log?.Invoke("기존 세션 종료");
                    _currentSession.Dispose();
                    _currentSession = null;
                }

                var session = new ClientSession(connection, _config, _capturer!, _encoder!, _input!);
                session.Disconnected += OnSessionDisconnected;
                _currentSession = session;
                ConnectionChanged?.Invoke(true);

                _ = Task.Run(() => session.RunAsync(), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }
            catch (Exception ex)
            {
                Log?.Invoke($"Accept 오류: {ex.Message}");
            }
        }
    }

    private void OnSessionDisconnected(ClientSession session)
    {
        Log?.Invoke($"연결 해제: {session.RemoteEndPoint}");
        if (_currentSession == session)
            _currentSession = null;
        ConnectionChanged?.Invoke(false);
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        Stop();
    }
}

