using System.Net.Sockets;
using RemoteDesktop.Common.Auth;
using RemoteDesktop.Common.Network;
using RemoteDesktop.Common.Protocol;

namespace RemoteDesktop.Client.Network;

/// <summary>Agent 접속 + 인증 + 패킷 수신</summary>
public class ClientConnection : IDisposable
{
    private TcpClient? _client;
    private TcpConnection? _connection;
    private CancellationTokenSource? _cts;
    private bool _disposed;

    public bool IsConnected => _connection?.IsConnected ?? false;
    public ushort ScreenWidth { get; private set; }
    public ushort ScreenHeight { get; private set; }

    public event Action<ScreenFullPayload>? ScreenReceived;
    public event Action<string>? Disconnected;
    public event Action<string>? Log;

    /// <summary>Agent 접속 + 인증</summary>
    public async Task<bool> ConnectAsync(string host, int port, string password)
    {
        _cts = new CancellationTokenSource();
        _client = new TcpClient();

        // 5초 타임아웃 연결
        using var connectCts = new CancellationTokenSource(5000);
        await _client.ConnectAsync(host, port, connectCts.Token);
        _connection = new TcpConnection(_client);

        Log?.Invoke($"TCP 연결 성공: {host}:{port}");

        // 챌린지 수신
        var challengePacket = await _connection.ReceiveAsync(_cts.Token);
        if (challengePacket.Type != PacketType.AuthChallenge)
            throw new Exception("잘못된 인증 프로토콜");

        var challenge = AuthChallengePayload.Deserialize(challengePacket.Payload);

        // 해시 계산 + 전송
        var hash = ChallengeAuth.ComputeHash(challenge.Nonce, password);
        var authReq = new AuthRequestPayload { Hash = hash };
        await _connection.SendAsync(
            new Packet(PacketType.AuthRequest, authReq.Serialize()), _cts.Token);

        // 응답 수신
        var responsePacket = await _connection.ReceiveAsync(_cts.Token);
        if (responsePacket.Type != PacketType.AuthResponse)
            throw new Exception("잘못된 인증 응답");

        var response = AuthResponsePayload.Deserialize(responsePacket.Payload);
        if (!response.Success)
            return false;

        ScreenWidth = response.Width;
        ScreenHeight = response.Height;

        Log?.Invoke($"인증 성공 (해상도: {ScreenWidth}x{ScreenHeight})");

        // 수신 루프 + 하트비트 시작
        _connection.StartHeartbeat();
        _ = Task.Run(ReceiveLoopAsync);

        return true;
    }

    private async Task ReceiveLoopAsync()
    {
        try
        {
            while (_cts != null && !_cts.IsCancellationRequested)
            {
                var packet = await _connection!.ReceiveAsync(_cts.Token);

                switch (packet.Type)
                {
                    case PacketType.ScreenFull:
                        var screen = ScreenFullPayload.Deserialize(packet.Payload);
                        ScreenWidth = screen.Width;
                        ScreenHeight = screen.Height;
                        ScreenReceived?.Invoke(screen);
                        break;

                    case PacketType.Heartbeat:
                        break;
                }
            }
        }
        catch (Exception ex) when (ex is IOException or OperationCanceledException or ObjectDisposedException)
        {
            Disconnected?.Invoke("연결이 끊어졌습니다.");
        }
    }

    /// <summary>패킷 전송</summary>
    public async Task SendAsync(Packet packet)
    {
        if (_connection != null)
            await _connection.SendAsync(packet, _cts?.Token ?? default);
    }

    public void Disconnect()
    {
        Dispose();
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        _cts?.Cancel();
        _cts?.Dispose();
        _connection?.Dispose();
        _client?.Dispose();
    }
}

