                var packet = await _connection!.ReceiveAsync(_cts.Token);

                switch (packet.Type)
                {
                    case PacketType.ScreenFull:
                        var screen = ScreenFullPayload.Deserialize(packet.Payload);
                        ScreenWidth = screen.Width;
                        ScreenHeight = screen.Height;
                        ScreenReceived?.Invoke(screen);
                        break;

                    case PacketType.Heartbeat:
                        break;
                }
            }
        }
        catch (Exception ex) when (ex is IOException or OperationCanceledException or ObjectDisposedException)
        {
            Disconnected?.Invoke("연결이 끊어졌습니다.");
        }
    }

    /// <summary>패킷 전송</summary>
    public async Task SendAsync(Packet packet)
    {
        if (_connection != null)
            await _connection.SendAsync(packet, _cts?.Token ?? default);
    }

    public void Disconnect()
    {
        Dispose();
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        _cts?.Cancel();
        _cts?.Dispose();
        _connection?.Dispose();
        _client?.Dispose();
    }
}

