using System.Diagnostics;
using RemoteDesktop.Common.Protocol;

namespace RemoteDesktop.Client.Input;

/// <summary>마우스/키 이벤트 → 패킷 변환 (좌표 정규화 + 마우스 쓰로틀)</summary>
public class InputMapper
{
    private readonly Func<Task, Task> _sendAction;
    private readonly Stopwatch _moveThrottle = Stopwatch.StartNew();
    private const int MOUSE_THROTTLE_MS = 16; // ~60Hz

    /// <summary>sendAction: Packet을 전송하는 콜백</summary>
    public InputMapper(Func<Packet, Task> sendAction)
    {
        _sendAction = p => sendAction(p);
    }

    /// <summary>마우스 이동 (화면 내 좌표를 정규화)</summary>
    public void OnMouseMove(int x, int y, int viewWidth, int viewHeight,
        int offsetX, int offsetY, int renderWidth, int renderHeight)
    {
        // 쓰로틀
        if (_moveThrottle.ElapsedMilliseconds < MOUSE_THROTTLE_MS)
            return;
        _moveThrottle.Restart();

        var (nx, ny) = Normalize(x, y, offsetX, offsetY, renderWidth, renderHeight);
        if (nx < 0 || nx > 1 || ny < 0 || ny > 1) return;

        var payload = new MouseMovePayload { NormalizedX = nx, NormalizedY = ny };
        _ = _sendAction(new Packet(PacketType.MouseMove, payload.Serialize()));
    }

    /// <summary>마우스 클릭</summary>
    public void OnMouseClick(int x, int y, int viewWidth, int viewHeight,
        int offsetX, int offsetY, int renderWidth, int renderHeight,
        MouseButtons button, bool isDown)
    {
        var (nx, ny) = Normalize(x, y, offsetX, offsetY, renderWidth, renderHeight);
        if (nx < 0 || nx > 1 || ny < 0 || ny > 1) return;

        byte btn = button switch
        {
            MouseButtons.Left => 0,
            MouseButtons.Right => 1,
            MouseButtons.Middle => 2,
            _ => 0
        };

        var payload = new MouseClickPayload
        {
            NormalizedX = nx,
            NormalizedY = ny,
            Button = btn,
            IsDown = isDown
        };
        _ = _sendAction(new Packet(PacketType.MouseClick, payload.Serialize()));
    }

    /// <summary>마우스 스크롤</summary>
    public void OnMouseScroll(int x, int y, int viewWidth, int viewHeight,
        int offsetX, int offsetY, int renderWidth, int renderHeight,
        int delta)
    {
        var (nx, ny) = Normalize(x, y, offsetX, offsetY, renderWidth, renderHeight);
        if (nx < 0 || nx > 1 || ny < 0 || ny > 1) return;

        var payload = new MouseScrollPayload
        {
            NormalizedX = nx,
            NormalizedY = ny,
            Delta = (short)delta
        };
        _ = _sendAction(new Packet(PacketType.MouseScroll, payload.Serialize()));
    }

    /// <summary>키보드 이벤트</summary>
    public void OnKeyEvent(Keys keyCode, bool isDown)
    {
        ushort vk = (ushort)keyCode;
        ushort scan = (ushort)MapVirtualKey(vk);
        bool ext = IsExtendedKey(keyCode);

        var payload = new KeyEventPayload
        {
            VirtualKey = vk,
            ScanCode = scan,
            IsDown = isDown,
            IsExtended = ext
        };
        _ = _sendAction(new Packet(PacketType.KeyEvent, payload.Serialize()));
    }

    /// <summary>좌표 정규화 (렌더 영역 기준 0~1)</summary>
    private static (float nx, float ny) Normalize(int x, int y,
        int offsetX, int offsetY, int renderWidth, int renderHeight)
    {
        float nx = (x - offsetX) / (float)renderWidth;
        float ny = (y - offsetY) / (float)renderHeight;
        return (nx, ny);
    }

    /// <summary>확장 키 여부</summary>
    private static bool IsExtendedKey(Keys key)
    {
        return key is Keys.RControlKey or Keys.RMenu or Keys.RShiftKey
            or Keys.Insert or Keys.Delete or Keys.Home or Keys.End
            or Keys.PageUp or Keys.PageDown
            or Keys.Up or Keys.Down or Keys.Left or Keys.Right
            or Keys.NumLock or Keys.PrintScreen or Keys.Pause;
    }

    [System.Runtime.InteropServices.DllImport("user32.dll")]
    private static extern uint MapVirtualKey(uint uCode, uint uMapType = 0);
}

