using System.Drawing;
using RemoteDesktop.Common.Protocol;

namespace RemoteDesktop.Client.Rendering;

/// <summary>JPEG 디코딩 + 비율 유지 렌더링</summary>
public class ScreenRenderer : IDisposable
{
    private Bitmap? _currentFrame;
    private readonly object _frameLock = new();
    private bool _disposed;

    // 렌더 영역 (비율 유지 후 실제 그려지는 영역)
    public int RenderX { get; private set; }
    public int RenderY { get; private set; }
    public int RenderWidth { get; private set; }
    public int RenderHeight { get; private set; }

    /// <summary>JPEG 데이터로 프레임 업데이트</summary>
    public void UpdateFrame(ScreenFullPayload screen)
    {
        var ms = new MemoryStream(screen.JpegData);
        var newFrame = new Bitmap(ms);

        lock (_frameLock)
        {
            _currentFrame?.Dispose();
            _currentFrame = newFrame;
        }
    }

    /// <summary>컨트롤에 비율 유지 렌더링</summary>
    public void Render(Graphics g, int clientWidth, int clientHeight)
    {
        Bitmap? frame;
        lock (_frameLock)
        {
            frame = _currentFrame;
        }

        if (frame == null)
        {
            g.Clear(Color.Black);
            return;
        }

        // 비율 유지 계산
        float srcRatio = (float)frame.Width / frame.Height;
        float dstRatio = (float)clientWidth / clientHeight;

        if (srcRatio > dstRatio)
        {
            // 소스가 더 넓음 → 좌우 맞춤, 상하 레터박스
            RenderWidth = clientWidth;
            RenderHeight = (int)(clientWidth / srcRatio);
        }
        else
        {
            // 소스가 더 좁음 → 상하 맞춤, 좌우 필러박스
            RenderHeight = clientHeight;
            RenderWidth = (int)(clientHeight * srcRatio);
        }
        RenderX = (clientWidth - RenderWidth) / 2;
        RenderY = (clientHeight - RenderHeight) / 2;

        g.Clear(Color.Black);
        lock (_frameLock)
        {
            if (_currentFrame != null)
            {
                g.InterpolationMode = System.Drawing.Drawing2D.InterpolationMode.Bilinear;
                g.DrawImage(_currentFrame, RenderX, RenderY, RenderWidth, RenderHeight);
            }
        }
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        lock (_frameLock)
        {
            _currentFrame?.Dispose();
        }
    }
}

