/// <summary>IP/포트/비밀번호 입력 폼</summary>
public partial class ConnectForm : Form
{
    public string Host => txtHost.Text.Trim();
    public int Port => int.TryParse(txtPort.Text, out var p) ? p : 9500;
    public string Password => txtPassword.Text;

    public ConnectForm()
    {
        InitializeComponent();
    }

    private void btnConnect_Click(object? sender, EventArgs e)
    {
        if (string.IsNullOrWhiteSpace(txtHost.Text))
        {
            MessageBox.Show("IP 주소를 입력하세요.", "연결", MessageBoxButtons.OK, MessageBoxIcon.Warning);
            return;
        }
        DialogResult = DialogResult.OK;
        Close();
    }

    private void btnCancel_Click(object? sender, EventArgs e)
    {
        DialogResult = DialogResult.Cancel;
        Close();
    }

    // Enter 키로 연결
    protected override bool ProcessCmdKey(ref Message msg, Keys keyData)
    {
        if (keyData == Keys.Enter)
        {
            btnConnect_Click(null, EventArgs.Empty);
            return true;
        }
        return base.ProcessCmdKey(ref msg, keyData);
    }
}

