using RemoteDesktop.Client.Input;
using RemoteDesktop.Client.Network;
using RemoteDesktop.Client.Rendering;
using RemoteDesktop.Common.Protocol;

namespace RemoteDesktop.Client.Forms;

/// <summary>원격 화면 표시 + 입력 전달 폼</summary>
public partial class ViewerForm : Form
{
    private readonly ClientConnection _connection;
    private readonly ScreenRenderer _renderer;
    private readonly InputMapper _inputMapper;
    private readonly System.Windows.Forms.Timer _renderTimer;

    public ViewerForm(ClientConnection connection)
    {
        InitializeComponent();

        _connection = connection;
        _renderer = new ScreenRenderer();
        _inputMapper = new InputMapper(p => _connection.SendAsync(p));

        // 화면 수신 이벤트
        _connection.ScreenReceived += OnScreenReceived;
        _connection.Disconnected += OnDisconnected;

        // 렌더 타이머 (30fps UI 갱신)
