using RemoteDesktop.Client.Forms;
using RemoteDesktop.Client.Network;

namespace RemoteDesktop.Client;

static class Program
{
    [STAThread]
    static void Main()
    {
        ApplicationConfiguration.Initialize();

        // 전역 예외 핸들러
        Application.ThreadException += (_, e) => LogCrash(e.Exception);
        AppDomain.CurrentDomain.UnhandledException += (_, e) =>
            LogCrash(e.ExceptionObject as Exception);

        while (true)
        {
            using var connectForm = new ConnectForm();
            if (connectForm.ShowDialog() != DialogResult.OK)
                break;

            var connection = new ClientConnection();
            try
            {
                var task = Task.Run(async () =>
                    await connection.ConnectAsync(connectForm.Host, connectForm.Port, connectForm.Password));

                bool success = task.GetAwaiter().GetResult();
                if (!success)
                {
                    MessageBox.Show("인증 실패: 비밀번호를 확인하세요.", "연결 실패",
                        MessageBoxButtons.OK, MessageBoxIcon.Error);
                    connection.Dispose();
                    continue;
                }

                using var viewerForm = new ViewerForm(connection);
                Application.Run(viewerForm);
                break; // 뷰어 닫으면 종료
            }
            catch (Exception ex)
            {
                MessageBox.Show($"연결 실패: {ex.Message}", "오류",
                    MessageBoxButtons.OK, MessageBoxIcon.Error);
                connection.Dispose();
            }
        }
    }

    private static void LogCrash(Exception? ex)
    {
        if (ex == null) return;
        var logPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "crash.log");
        var entry = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] {ex.Source}: {ex.Message}\n{ex.StackTrace}\n\n";
        try { File.AppendAllText(logPath, entry); } catch { }
    }
}

using RemoteDesktop.Agent.Server;

namespace RemoteDesktop.Agent;

/// <summary>시스템 트레이 앱 컨텍스트</summary>
public class AgentApplicationContext : ApplicationContext
{
    private readonly NotifyIcon _notifyIcon;
    private readonly AgentServer _server;
    private readonly AgentConfig _config;

    public AgentApplicationContext()
    {
        _config = AgentConfig.Load();

        // 트레이 아이콘
        _notifyIcon = new NotifyIcon
        {
            Text = "RemoteDesktop Agent",
            Icon = SystemIcons.Shield,
            Visible = true,
            ContextMenuStrip = CreateMenu()
        };

        // 서버 시작
        _server = new AgentServer(_config);
        _server.Log += msg => System.Diagnostics.Debug.WriteLine($"[Agent] {msg}");
        _server.ConnectionChanged += connected =>
        {
            _notifyIcon.Icon = connected ? SystemIcons.Information : SystemIcons.Shield;
            _notifyIcon.Text = connected ? "RemoteDesktop Agent (연결됨)" : "RemoteDesktop Agent";
        };

        _server.Start();
        _notifyIcon.ShowBalloonTip(2000, "RemoteDesktop Agent",
            $"포트 {_config.Port}에서 대기 중", ToolTipIcon.Info);
    }

    private ContextMenuStrip CreateMenu()
    {
        var menu = new ContextMenuStrip();
        menu.Items.Add($"포트: {_config.Port}", null, null!).Enabled = false;
        menu.Items.Add("-");
        menu.Items.Add("종료", null, (_, _) =>
        {
            _server.Stop();
            _notifyIcon.Visible = false;
            ExitThread();
        });
        return menu;
    }

    protected override void Dispose(bool disposing)
    {
        if (disposing)
        {
            _server.Dispose();
            _notifyIcon.Dispose();
        }
        base.Dispose(disposing);
    }
}

