/// </summary>
[StructLayout(LayoutKind.Sequential, Pack = 4)]
public readonly record struct RawRect
{
    public RawRect(int left, int top, int right, int bottom)
    {
        Left = left;
        Top = top;
        Right = right;
        Bottom = bottom;
    }

    /// <summary>
    /// The left position.
    /// </summary>
    public readonly int Left;

    /// <summary>
    /// The top position.
    /// </summary>
    public readonly int Top;

    /// <summary>
    /// The right position
    /// </summary>
    public readonly int Right;

    /// <summary>
    /// The bottom position.
    /// </summary>
    public readonly int Bottom;

    /// <summary>
    /// Performs an implicit conversion from <see cre ="RawRect"/> to <see cref="RectI" />.
    /// </summary>
    /// <param name="value">The value to convert.</param>
    /// <returns>The result of the conversion.</returns>
    public static implicit operator RectI(in RawRect value) => RectI.FromLTRB(value.Left, value.Top, value.Right, value.Bottom);

    /// <summary>
    /// Performs an implicit conversion from <see cre ="RectI"/> to <see cref="RawRect" />.
    /// </summary>
    /// <param name="value">The value to convert.</param>
    /// <returns>The result of the conversion.</returns>
    public static implicit operator RawRect(in RectI value) => new(value.Left, value.Top, value.Right, value.Bottom);

    /// <summary>
    /// Performs an implicit conversion from <see cre ="RawRect"/> to <see cref="System.Drawing.Rectangle" />.
    /// </summary>
    /// <param name="value">The value to convert.</param>
    /// <returns>The result of the conversion.</returns>
    public static implicit operator System.Drawing.Rectangle(in RawRect value) => System.Drawing.Rectangle.FromLTRB(value.Left, value.Top, value.Right, value.Bottom);

    /// <summary>
    /// Performs an implicit conversion from <see cre ="System.Drawing.Rectangle"/> to <see cref="RawRect" />.
    /// </summary>
    /// <param name="value">The value to convert.</param>
    /// <returns>The result of the conversion.</returns>
    public static implicit operator RawRect(in System.Drawing.Rectangle value) => new(value.Left, value.Top, value.Right, value.Bottom);

#if WINDOWS
    public static implicit operator RawRect(in Windows.Foundation.Rect value)
    {
        if (value.Left > int.MaxValue)
            throw new ArgumentOutOfRangeException(nameof(value.Left));

        if (value.Top > int.MaxValue)
            throw new ArgumentOutOfRangeException(nameof(value.Top));

        if (value.Right > int.MaxValue)
            throw new ArgumentOutOfRangeException(nameof(value.Right));

        if (value.Bottom > int.MaxValue)
            throw new ArgumentOutOfRangeException(nameof(value.Bottom));

        return new((int)value.Left, (int)value.Top, (int)value.Right, (int)value.Bottom);
    }
#endif
}

﻿using SharpGen.Runtime;
using System;
using System.Drawing;
using System.Drawing.Imaging;
using System.Threading;
using Vortice.Direct3D;
using Vortice.Direct3D11;
using Vortice.DXGI;

namespace VorticeCore
{
    class Program
    {
        private static readonly FeatureLevel[] s_featureLevels = new[]
        {
            FeatureLevel.Level_11_0,
            FeatureLevel.Level_10_1,
            FeatureLevel.Level_10_0,
            FeatureLevel.Level_9_3,
            FeatureLevel.Level_9_2,
            FeatureLevel.Level_9_1,
        };

        static void Main(string[] args)
        {
            var img = CaptureScreenFrames(0);
            img.Save("bitmap.png", ImageFormat.Png);
            Console.ReadLine();
        }

        public static Bitmap CaptureScreenFrames(int screenId)
        {
            var factory = DXGI.CreateDXGIFactory1<IDXGIFactory1>();
            var adapter = factory.GetAdapter(0);
            var output = adapter.GetOutput(screenId);
            var output1 = output.QueryInterface<IDXGIOutput1>();
            D3D11.D3D11CreateDevice(adapter, DriverType.Unknown, DeviceCreationFlags.None, s_featureLevels, out var device);

            var bounds = output1.Description.DesktopCoordinates;
            var textureDesc = new Texture2DDescription
            {
                CpuAccessFlags = CpuAccessFlags.Read,
                BindFlags = BindFlags.None,
                Format = Format.B8G8R8A8_UNorm,
                Width = bounds.Right - bounds.Left,
                Height = bounds.Bottom - bounds.Top,
                OptionFlags = ResourceOptionFlags.None,
                MipLevels = 1,
                ArraySize = 1,
                SampleDescription = { Count = 1, Quality = 0 },
                Usage = Vortice.Direct3D11.Usage.Staging
            };

            var duplication = output1.DuplicateOutput(device);
            var currentFrame = device.CreateTexture2D(textureDesc);

            Thread.Sleep(100);

            duplication.AcquireNextFrame(500, out var frameInfo, out var desktopResource);

            var tempTexture = desktopResource.QueryInterface<ID3D11Texture2D>();
            device.ImmediateContext.CopyResource(currentFrame, tempTexture);

            var dataBox = device.ImmediateContext.Map(currentFrame, 0, MapMode.Read, Vortice.Direct3D11.MapFlags.None);

            var frame = new Bitmap(1920, 1080, PixelFormat.Format32bppRgb);
            var mapDest = frame.LockBits(new Rectangle(0, 0, 1920, 1080), ImageLockMode.WriteOnly, frame.PixelFormat);
            for (int y = 0, sizeInBytesToCopy = 1920 * 4; y < 1080; y++)
            {
                MemoryHelpers.CopyMemory(mapDest.Scan0 + y * mapDest.Stride, dataBox.DataPointer + y * dataBox.RowPitch, sizeInBytesToCopy);
            }
            frame.UnlockBits(mapDest);

            return frame;
        }
    }
}

