using System.Drawing;
using System.Drawing.Imaging;
using System.Runtime.InteropServices;
using Vortice.Direct3D;
using Vortice.Direct3D11;
using Vortice.DXGI;

namespace RemoteDesktop.Agent.Capture;

/// <summary>DXGI Desktop Duplication 화면 캡처</summary>
public class DxgiScreenCapturer : IScreenCapturer
{
    private ID3D11Device? _device;
    private ID3D11DeviceContext? _context;
    private IDXGIOutputDuplication? _duplication;
    private ID3D11Texture2D? _stagingTexture;

    public int Width { get; private set; }
    public int Height { get; private set; }

    private bool _disposed;

    public DxgiScreenCapturer()
    {
        Initialize();
    }

    private void Initialize()
    {
        // D3D11 디바이스 생성
        D3D11.D3D11CreateDevice(
            null,
            DriverType.Hardware,
            DeviceCreationFlags.BgraSupport,
            null,
            out _device,
            out _context);

        if (_device == null || _context == null)
            throw new Exception("D3D11 디바이스 생성 실패");

        // DXGI 팩토리에서 주 모니터 출력 가져오기
        using var dxgiDevice = _device.QueryInterface<IDXGIDevice>();
        using var adapter = dxgiDevice.GetAdapter();
        using var output = adapter.EnumOutputs(0);
        using var output1 = output.QueryInterface<IDXGIOutput1>();

        var outputDesc = output.Description;
        Width = outputDesc.DesktopCoordinates.Right - outputDesc.DesktopCoordinates.Left;
        Height = outputDesc.DesktopCoordinates.Bottom - outputDesc.DesktopCoordinates.Top;

        // Desktop Duplication 생성
        _duplication = output1.DuplicateOutput(_device);

        // 스테이징 텍스처 (GPU→CPU 복사용)
        var stagingDesc = new Texture2DDescription
        {
            Width = Width,
            Height = Height,
            MipLevels = 1,
            ArraySize = 1,
            Format = Vortice.DXGI.Format.B8G8R8A8_UNorm,
            SampleDescription = new SampleDescription(1, 0),
            Usage = ResourceUsage.Staging,
            CPUAccessFlags = CpuAccessFlags.Read,
            BindFlags = BindFlags.None
        };
        _stagingTexture = _device.CreateTexture2D(stagingDesc);
    }

    public Bitmap? CaptureFrame()
    {
        if (_duplication == null || _context == null || _stagingTexture == null)
            return null;

        IDXGIResource? resource = null;
        try
        {
            // 프레임 획득 (16ms 타임아웃)
            var result = _duplication.AcquireNextFrame(16, out _, out resource);
            if (result.Failure || resource == null)
                return null;

            using var texture = resource.QueryInterface<ID3D11Texture2D>();
            _context.CopyResource(_stagingTexture, texture);

            // GPU→CPU 매핑
            var mapped = _context.Map(_stagingTexture, 0, MapMode.Read);
            try
            {
                var bitmap = new Bitmap(Width, Height, PixelFormat.Format32bppArgb);
                var bmpData = bitmap.LockBits(
                    new Rectangle(0, 0, Width, Height),
                    ImageLockMode.WriteOnly,
                    PixelFormat.Format32bppArgb);

                // 행 단위 복사 (stride가 다를 수 있음)
                for (int y = 0; y < Height; y++)
                {
                    var srcPtr = mapped.DataPointer + y * mapped.RowPitch;
                    var dstPtr = bmpData.Scan0 + y * bmpData.Stride;
                    Buffer.MemoryCopy(srcPtr.ToPointer(), dstPtr.ToPointer(),
                        bmpData.Stride, Width * 4);
                }

                bitmap.UnlockBits(bmpData);
                return bitmap;
            }
            finally
            {
                _context.Unmap(_stagingTexture, 0);
            }
        }
        catch (SharpGen.Runtime.SharpGenException ex) when (
            ex.ResultCode.Code == Vortice.DXGI.ResultCode.AccessLost.Code)
        {
            // 해상도 변경/절전 복귀 → 재초기화
            Reinitialize();
            return null;
        }
        finally
        {
            resource?.Dispose();
            try { _duplication?.ReleaseFrame(); } catch { }
        }
    }

    private void Reinitialize()
    {
        CleanupResources();
        try { Initialize(); }
        catch { /* 다음 프레임에서 재시도 */ }
    }

    private void CleanupResources()
    {
        _stagingTexture?.Dispose();
        _stagingTexture = null;
        _duplication?.Dispose();
        _duplication = null;
        _context?.Dispose();
        _context = null;
        _device?.Dispose();
        _device = null;
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        CleanupResources();
        GC.SuppressFinalize(this);
    }
}

using RemoteDesktop.Agent.Capture;
using RemoteDesktop.Agent.Encoding;
using RemoteDesktop.Agent.Input;
using RemoteDesktop.Common.Auth;
using RemoteDesktop.Common.Network;
using RemoteDesktop.Common.Protocol;

namespace RemoteDesktop.Agent.Server;

/// <summary>클라이언트 세션 (인증/캡처/입력 처리)</summary>
public class ClientSession : IDisposable
{
    private readonly TcpConnection _connection;
    private readonly AgentConfig _config;
    private readonly IScreenCapturer _capturer;
    private readonly JpegEncoder _encoder;
    private readonly InputSimulator _input;

    private System.Threading.Timer? _captureTimer;
    private readonly object _captureLock = new();
    private readonly CancellationTokenSource _cts = new();
    private bool _authenticated;
    private bool _disposed;

    public event Action<ClientSession>? Disconnected;
    public string RemoteEndPoint => _connection.RemoteEndPoint;

    public ClientSession(TcpConnection connection, AgentConfig config,
        IScreenCapturer capturer, JpegEncoder encoder, InputSimulator input)
    {
        _connection = connection;
        _config = config;
        _capturer = capturer;
        _encoder = encoder;
        _input = input;
    }

    /// <summary>세션 시작 (인증 → 수신 루프)</summary>
    public async Task RunAsync()
    {
        try
        {
            // 챌린지-리스펀스 인증
            if (!await AuthenticateAsync())
            {
                Dispose();
                return;
            }

            // 화면 스트리밍 시작
            StartCapture();
            _connection.StartHeartbeat();

            // 입력 수신 루프
            await ReceiveLoopAsync();
        }
        catch (Exception ex) when (ex is IOException or OperationCanceledException)
        {
            // 연결 끊김
        }
        finally
        {
            Disconnected?.Invoke(this);
            Dispose();
        }
    }

    private async Task<bool> AuthenticateAsync()
    {
        var ct = _cts.Token;

        // nonce 전송
        var nonce = ChallengeAuth.GenerateNonce();
        var challengePayload = new AuthChallengePayload { Nonce = nonce };
        await _connection.SendAsync(
            new Packet(PacketType.AuthChallenge, challengePayload.Serialize()), ct);

        // 클라이언트 해시 수신
        var packet = await _connection.ReceiveAsync(ct);
        if (packet.Type != PacketType.AuthRequest || packet.Payload.Length != 32)
        {
            await SendAuthResponse(false);
            return false;
        }

        var authReq = AuthRequestPayload.Deserialize(packet.Payload);
        bool success = ChallengeAuth.Verify(nonce, _config.Password, authReq.Hash);
        await SendAuthResponse(success);

        _authenticated = success;
        return success;
    }

    private async Task SendAuthResponse(bool success)
    {
        var response = new AuthResponsePayload
        {
            Success = success,
            Width = (ushort)_capturer.Width,
            Height = (ushort)_capturer.Height
        };
        await _connection.SendAsync(
            new Packet(PacketType.AuthResponse, response.Serialize()), _cts.Token);
    }

    private void StartCapture()
    {
        _captureTimer = new Timer(CaptureCallback, null,
            0, _config.CaptureIntervalMs);
    }

    private async void CaptureCallback(object? state)
    {
        if (_disposed || !_authenticated) return;

        // 재진입 방지
        if (!Monitor.TryEnter(_captureLock)) return;
        try
        {
            var bitmap = _capturer.CaptureFrame();
            if (bitmap == null) return;

            byte[] jpeg;
            using (bitmap)
            {
                jpeg = _encoder.Encode(bitmap);
            }

            var payload = new ScreenFullPayload
            {
                Width = (ushort)_capturer.Width,
                Height = (ushort)_capturer.Height,
                JpegData = jpeg
            };

            await _connection.SendAsync(
                new Packet(PacketType.ScreenFull, payload.Serialize()), _cts.Token);
        }
        catch (Exception ex) when (ex is IOException or ObjectDisposedException)
        {
            Dispose();
        }
        finally
        {
            Monitor.Exit(_captureLock);
        }
    }

    private async Task ReceiveLoopAsync()
    {
        var ct = _cts.Token;
        while (!ct.IsCancellationRequested)
        {
            var packet = await _connection.ReceiveAsync(ct);

            switch (packet.Type)
            {
                case PacketType.MouseMove:
                    var move = MouseMovePayload.Deserialize(packet.Payload);
                    _input.MouseMove(move.NormalizedX, move.NormalizedY);
                    break;

                case PacketType.MouseClick:
                    var click = MouseClickPayload.Deserialize(packet.Payload);
                    _input.MouseClick(click.NormalizedX, click.NormalizedY,
                        click.Button, click.IsDown);
                    break;

                case PacketType.MouseScroll:
                    var scroll = MouseScrollPayload.Deserialize(packet.Payload);
                    _input.MouseScroll(scroll.NormalizedX, scroll.NormalizedY, scroll.Delta);
                    break;

                case PacketType.KeyEvent:
                    var key = KeyEventPayload.Deserialize(packet.Payload);
                    _input.KeyEvent(key.VirtualKey, key.ScanCode, key.IsDown, key.IsExtended);
                    break;

                case PacketType.Heartbeat:
                    // 무시 (연결 유지 확인)
                    break;
            }
        }
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;
        _captureTimer?.Dispose();
        _cts.Cancel();
        _cts.Dispose();
        _connection.Dispose();
    }
}

